#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int k; cin >> k;
    int A = 0, B = 0;
    int a; cin >> a;
    for (int i = 0; i < a; i++) { int x; cin >> x; A |= (1 << x); }
    int b; cin >> b;
    for (int i = 0; i < b; i++) { int x; cin >> x; B |= (1 << x); }
    cout << __builtin_popcount(A | B) << ' '
         << __builtin_popcount(A & B) << ' '
         << __builtin_popcount(A & ~B) << ' '
         << __builtin_popcount(A ^ B) << "\n";
    return 0;
}
